const DEFAULT_API_BASE_PATH = '/api';

export function getApiBaseUrl() {
  const configuredBaseUrl = process.env.REACT_APP_API_BASE_URL;
  const normalizedConfiguredBaseUrl = configuredBaseUrl?.replace(/\/+$/, '');
  const browserOrigin = typeof window !== 'undefined' ? window.location?.origin : '';
  const browserHostname = typeof window !== 'undefined' ? window.location?.hostname : '';
  const isLocalDevelopmentHost =
    browserHostname === 'localhost' || browserHostname === '127.0.0.1';

  // Keep explicit API overrides for local development, but default deployed builds
  // to same-origin `/api` so auth requests do not depend on cross-origin CORS.
  if (normalizedConfiguredBaseUrl && isLocalDevelopmentHost) {
    return normalizedConfiguredBaseUrl;
  }

  if (browserOrigin) {
    return `${browserOrigin}${DEFAULT_API_BASE_PATH}`;
  }

  return normalizedConfiguredBaseUrl || DEFAULT_API_BASE_PATH;
}

export function getApiBaseUrlCandidates() {
  const configuredBaseUrl = process.env.REACT_APP_API_BASE_URL?.replace(/\/+$/, '');
  const browserOrigin = typeof window !== 'undefined' ? window.location?.origin : '';
  const sameOriginBaseUrl = browserOrigin ? `${browserOrigin}${DEFAULT_API_BASE_PATH}` : DEFAULT_API_BASE_PATH;
  const candidates = [];

  if (configuredBaseUrl) {
    candidates.push(configuredBaseUrl);
  }

  if (!candidates.includes(sameOriginBaseUrl)) {
    candidates.push(sameOriginBaseUrl);
  }

  if (!candidates.includes(DEFAULT_API_BASE_PATH)) {
    candidates.push(DEFAULT_API_BASE_PATH);
  }

  return candidates;
}

export function buildApiUrl(path) {
  const normalizedPath = path.startsWith('/') ? path : `/${path}`;
  return `${getApiBaseUrl()}${normalizedPath}`;
}

export function buildApiUrlCandidates(path) {
  const normalizedPath = path.startsWith('/') ? path : `/${path}`;
  return getApiBaseUrlCandidates().map((baseUrl) => `${baseUrl}${normalizedPath}`);
}
